package agent

import (
	"context"
	"errors"
	"fmt"
	"path/filepath"
	"strings"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/trackerpaths"
)

// MarkResultExecutionError preserves a populated worker result as a structured
// attempt failure. Callers use this when ExecuteBeadWithConfig returned both a
// result and an error; the presence of the result means DDx has enough
// execution context to report the attempt instead of aborting the process.
func MarkResultExecutionError(res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if res.Outcome == "" {
		res.Outcome = ExecuteBeadOutcomeTaskFailed
	}
	if res.Reason == "" {
		res.Reason = err.Error()
	}
	if res.Error == "" {
		res.Error = err.Error()
	}
	if res.Status == "" || res.Status == ExecuteBeadStatusNoChanges {
		res.Status = ClassifyExecuteBeadStatus("error", res.ExitCode, res.Reason)
	}
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
	if res.FailureMode == "" {
		res.FailureMode = FailureModeUnknown
	}
	// A pre-dispatch provider-boundary failure carries its typed classification
	// on the error (ddx-3b721804). Prefer it so the report's outcome_reason is
	// the precise provider taxonomy (provider_auth, provider_model_unavailable,
	// ...) rather than the coarse worker-level bucket.
	var pfErr *ProviderFailureError
	if errors.As(err, &pfErr) && pfErr.Failure.Reason != "" {
		res.FailureMode = pfErr.Failure.Reason
	}
}

// MarkResultLandError records a coordinator/landing failure on a completed
// worker result. When possible it first pins ResultRev under refs/ddx/iterations
// so the worker's commit remains reachable even though the target branch did
// not advance cleanly.
func MarkResultLandError(projectRoot string, res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if markReconciledAlreadyLanded(projectRoot, res, err) {
		return
	}
	reason := "land coordination failed: " + err.Error()
	if action, ok := classifyLandCoordinationAction(err.Error()); ok {
		switch action {
		case landCoordinationActionRetryLand:
			reason = "land coordination retry: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_retry"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandRetry
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandRetry
			return
		case landCoordinationActionOperatorAttention:
			reason = "land coordination operator attention: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_operator_attention"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandOperatorAttention
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandOperatorAttention
			return
		}
	}
	preserveResultRefForLandError(projectRoot, res, &reason)
	res.Outcome = "error"
	res.Reason = reason
	res.Error = err.Error()
	res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	res.OrchestratorStatus = res.Status
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = classifyLandingFailureMode(res.Outcome, res.Reason, res.GateResults, res.FailureMode)
}

func preserveResultRefForLandError(projectRoot string, res *ExecuteBeadResult, reason *string) {
	if res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev {
		return
	}
	preserveRef := landIterationRef(res.BeadID, res.AttemptID, res.BaseRev)
	if upErr := (RealLandingGitOps{}).UpdateRefTo(projectRoot, preserveRef, res.ResultRev, ""); upErr == nil {
		res.PreserveRef = preserveRef
	} else if reason != nil {
		*reason = fmt.Sprintf("%s; preserving result failed: %v", *reason, upErr)
	}
}

type landCoordinationAction string

const (
	landCoordinationActionRetryLand         landCoordinationAction = "retry-land"
	landCoordinationActionOperatorAttention landCoordinationAction = "operator-attention"
)

func markReconciledAlreadyLanded(projectRoot string, res *ExecuteBeadResult, err error) bool {
	if projectRoot == "" || res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev || err == nil {
		return false
	}
	if !strings.Contains(strings.ToLower(err.Error()), "cannot lock ref") {
		return false
	}
	targets := landCoordinationTargetRefs(err.Error())
	targets = append(targets, "HEAD")
	for _, target := range targets {
		tip, ok := resultReachableFromRef(projectRoot, res.ResultRev, target)
		if !ok {
			continue
		}
		if res.ImplementationRev == "" {
			res.ImplementationRev = res.ResultRev
		}
		res.ResultRev = tip
		res.LandedRev = tip
		res.Outcome = "merged"
		res.Reason = "land coordination reconciled: result already landed"
		res.Error = err.Error()
		res.Status = ExecuteBeadStatusSuccess
		res.OrchestratorStatus = res.Status
		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
		res.FailureMode = ""
		return true
	}
	return false
}

func resultReachableFromRef(projectRoot, resultRev, ref string) (string, bool) {
	tipOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", ref).Output()
	if err != nil {
		return "", false
	}
	tip := strings.TrimSpace(string(tipOut))
	if tip == "" {
		return "", false
	}
	err = internalgit.Command(context.Background(), projectRoot, "merge-base", "--is-ancestor", resultRev, tip).Run()
	return tip, err == nil
}

func landCoordinationTargetRefs(msg string) []string {
	var refs []string
	for _, token := range strings.FieldsFunc(msg, func(r rune) bool {
		return r == '\'' || r == '"' || r == ':' || r == ' ' || r == '\n' || r == '\t'
	}) {
		token = strings.TrimSpace(token)
		if strings.HasPrefix(token, "refs/heads/") {
			refs = append(refs, token)
		}
	}
	return refs
}

func classifyLandCoordinationAction(msg string) (landCoordinationAction, bool) {
	lower := strings.ToLower(msg)
	if strings.Contains(lower, "staged changes after waiting") {
		paths := stagedPathsFromLandError(msg)
		if len(paths) > 0 && allGeneratedLandCoordinationPaths(paths) {
			return landCoordinationActionRetryLand, true
		}
		return landCoordinationActionOperatorAttention, true
	}
	if strings.Contains(lower, "cannot lock ref") {
		return landCoordinationActionRetryLand, true
	}
	return "", false
}

func stagedPathsFromLandError(msg string) []string {
	lines := strings.Split(msg, "\n")
	if len(lines) <= 1 {
		return nil
	}
	var paths []string
	for _, line := range lines[1:] {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if tab := strings.IndexByte(line, '\t'); tab >= 0 {
			line = line[tab+1:]
		}
		if p := strings.TrimSpace(line); p != "" {
			paths = append(paths, filepath.ToSlash(p))
		}
	}
	return paths
}

func allGeneratedLandCoordinationPaths(paths []string) bool {
	for _, p := range paths {
		if trackerpaths.IsManagedTrackerPath(p) ||
			strings.HasPrefix(p, ".ddx/executions/") ||
			strings.HasPrefix(p, ".ddx/runs/") ||
			strings.HasPrefix(p, ".ddx/metrics/") ||
			strings.HasPrefix(p, ".ddx/attachments/") {
			continue
		}
		return false
	}
	return true
}

// ReportFromExecuteBeadResult maps the detailed worker/orchestrator result
// into the loop-facing report shape used by ddx work and ddx try.
func ReportFromExecuteBeadResult(res *ExecuteBeadResult, powerClass string) ExecuteBeadReport {
	if res == nil {
		return ExecuteBeadReport{}
	}
	return ExecuteBeadReport{
		BeadID:                      res.BeadID,
		AttemptID:                   res.AttemptID,
		WorkerID:                    res.WorkerID,
		Harness:                     res.Harness,
		Provider:                    res.Provider,
		Model:                       res.Model,
		ActualPower:                 res.ActualPower,
		PredictedPower:              res.PredictedPower,
		PredictedSpeedTPS:           res.PredictedSpeedTPS,
		PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
		PredictedCostSource:         res.PredictedCostSource,
		Status:                      res.Status,
		Detail:                      res.Detail,
		Error:                       res.Error,
		Stderr:                      res.Stderr,
		RateLimitBudget:             res.RateLimitBudget,
		SessionID:                   res.SessionID,
		BaseRev:                     res.BaseRev,
		ResultRev:                   res.ResultRev,
		ImplementationRev:           res.ImplementationRev,
		LandedRev:                   res.LandedRev,
		TargetBranch:                res.TargetBranch,
		EvidenceRev:                 res.EvidenceRev,
		ProjectRoot:                 res.ProjectRoot,
		PreserveRef:                 res.PreserveRef,
		CandidateRef:                res.CandidateRef,
		CycleIndex:                  res.CycleIndex,
		NoChangesRationale:          res.NoChangesRationale,
		CycleTrace:                  append([]ExecutionCycleTrace(nil), res.CycleTrace...),
		PowerClass:                  powerClass,
		CostUSD:                     res.CostUSD,
		DurationMS:                  int64(res.DurationMS),
		ResourceExhausted:           res.ResourceExhausted,
		OutcomeReason:               res.FailureMode,
	}
}

package failclass

import (
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// TestClassifyTable is the normative failure-classification table test (AC1).
// Every attempt Outcome maps to exactly one Action.
func TestClassifyTable(t *testing.T) {
	cases := []struct {
		name    string
		outcome Outcome
		ctx     ClassifyContext
		want    Action
	}{
		{"success", OutcomeSuccess, ClassifyContext{}, ActionCloseBead},
		{"already_satisfied", OutcomeAlreadySatisfied, ClassifyContext{}, ActionCloseBead},
		{"no_changes", OutcomeNoChanges, ClassifyContext{}, ActionCloseOrUnclaim},
		{"genuine_failure_middle", OutcomeGenuineFailure, ClassifyContext{AtMaxTier: false}, ActionEscalateTier},
		{"genuine_failure_max", OutcomeGenuineFailure, ClassifyContext{AtMaxTier: true}, ActionOperatorAttention},
		{"dirty_worktree", OutcomeDirtyWorktree, ClassifyContext{}, ActionResetRetrySameTier},
		{"transport", OutcomeTransport, ClassifyContext{}, ActionRerouteSameTier},
		{"quota", OutcomeQuota, ClassifyContext{}, ActionGlobalCooldown},
		{"auth", OutcomeAuth, ClassifyContext{}, ActionOperatorAttention},
		{"setup", OutcomeSetup, ClassifyContext{}, ActionOperatorAttention},
		{"timeout_first", OutcomeTimeout, ClassifyContext{SameTierRetried: false}, ActionResetRetrySameTier},
		{"timeout_second", OutcomeTimeout, ClassifyContext{SameTierRetried: true}, ActionOperatorAttention},
		{"merge_conflict", OutcomeMergeConflict, ClassifyContext{}, ActionUnclaimRetryLater},
		{"unknown", Outcome("something_new"), ClassifyContext{}, ActionOperatorAttention},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := Classify(tc.outcome, tc.ctx); got != tc.want {
				t.Fatalf("Classify(%q, %+v) = %q, want %q", tc.outcome, tc.ctx, got, tc.want)
			}
		})
	}
}

// TestOnlyGenuineFailureEscalates verifies that exactly one outcome can
// escalate — a genuine failure below the max tier — and that no_changes, dirty,
// transport, quota, and auth never escalate (AC2).
func TestOnlyGenuineFailureEscalates(t *testing.T) {
	// The only escalating row.
	if act := Classify(OutcomeGenuineFailure, ClassifyContext{AtMaxTier: false}); !act.Escalates() {
		t.Fatalf("genuine failure below max tier should escalate, got %q", act)
	}

	nonEscalating := []Outcome{
		OutcomeNoChanges,
		OutcomeDirtyWorktree,
		OutcomeTransport,
		OutcomeQuota,
		OutcomeAuth,
	}
	for _, outcome := range nonEscalating {
		for _, atMax := range []bool{false, true} {
			act := Classify(outcome, ClassifyContext{AtMaxTier: atMax})
			if act.Escalates() {
				t.Fatalf("outcome %q (atMaxTier=%v) must not escalate, got %q", outcome, atMax, act)
			}
		}
	}

	// A genuine failure at the max tier must not escalate either.
	if act := Classify(OutcomeGenuineFailure, ClassifyContext{AtMaxTier: true}); act.Escalates() {
		t.Fatalf("max-tier genuine failure must not escalate, got %q", act)
	}
}

// TestEscalateSingleOneHop verifies the single one-hop middle->max escalation
// and that it is idempotent: a second escalation is a no-op (AC2).
func TestEscalateSingleOneHop(t *testing.T) {
	next, escalated := Escalate(TierMiddle)
	if !escalated || next != TierMax {
		t.Fatalf("Escalate(TierMiddle) = (%v, %v), want (TierMax, true)", next, escalated)
	}

	// Already at max: no further escalation (exactly one middle->max).
	if again, ok := Escalate(next); ok || again != TierMax {
		t.Fatalf("Escalate(TierMax) = (%v, %v), want (TierMax, false)", again, ok)
	}

	// Low never escalates (escalation is the single middle->max edge only).
	if low, ok := Escalate(TierLow); ok || low != TierLow {
		t.Fatalf("Escalate(TierLow) = (%v, %v), want (TierLow, false)", low, ok)
	}
}

// TestPoolMaxInFlightCapConcurrent verifies the per-pool in-flight max-attempt
// cap holds under concurrent failures, preventing a multi-worker stampede
// (AC3). The test is bounded: a fixed number of goroutines, a WaitGroup
// barrier, and no sleeps.
func TestPoolMaxInFlightCapConcurrent(t *testing.T) {
	const (
		capLimit = 3
		workers  = 50
	)
	p := NewPool("default", capLimit)

	var acquired int64
	var wg sync.WaitGroup
	wg.Add(workers)
	for i := 0; i < workers; i++ {
		go func() {
			defer wg.Done()
			// Acquire and hold the slot (do not Release) so the cap is the
			// hard ceiling on simultaneous in-flight attempts.
			if p.Acquire() {
				atomic.AddInt64(&acquired, 1)
			}
		}()
	}
	wg.Wait()

	if got := atomic.LoadInt64(&acquired); got != capLimit {
		t.Fatalf("concurrent Acquire granted %d slots, want cap %d", got, capLimit)
	}
	if got := p.InFlight(); got != capLimit {
		t.Fatalf("InFlight() = %d, want %d", got, capLimit)
	}

	// Releasing one slot frees exactly one acquisition.
	p.Release()
	if !p.Acquire() {
		t.Fatal("Acquire after Release should succeed")
	}
	if got := p.InFlight(); got != capLimit {
		t.Fatalf("InFlight() after release+acquire = %d, want %d", got, capLimit)
	}
}

// TestPoolQuotaGlobalCooldown verifies that quota exhaustion drives a global
// per-pool cooldown (not a per-bead mutation): while in cooldown no worker can
// acquire a slot, and acquisition resumes once the cooldown elapses (AC4). A
// fake clock keeps the test bounded with no real sleeps.
func TestPoolQuotaGlobalCooldown(t *testing.T) {
	base := time.Unix(1_700_000_000, 0)
	current := base
	p := NewPool("default", 5)
	p.SetClock(func() time.Time { return current })

	// A quota outcome routes to a global cooldown.
	if act := Classify(OutcomeQuota, ClassifyContext{}); act != ActionGlobalCooldown {
		t.Fatalf("quota outcome = %q, want %q", act, ActionGlobalCooldown)
	}

	// Apply the cooldown; the whole pool is now unavailable to every worker.
	p.EnterCooldown(30 * time.Second)
	if !p.InCooldown() {
		t.Fatal("pool should be in cooldown after EnterCooldown")
	}
	if p.Acquire() {
		t.Fatal("Acquire must fail while the pool is in global cooldown")
	}
	if got := p.InFlight(); got != 0 {
		t.Fatalf("InFlight() during cooldown = %d, want 0 (no slot taken)", got)
	}

	// Before the window elapses, still blocked.
	current = base.Add(29 * time.Second)
	if p.Acquire() {
		t.Fatal("Acquire must fail before the cooldown window elapses")
	}

	// After the window elapses, acquisition resumes.
	current = base.Add(31 * time.Second)
	if p.InCooldown() {
		t.Fatal("pool should not be in cooldown after the window elapses")
	}
	if !p.Acquire() {
		t.Fatal("Acquire should succeed after the cooldown elapses")
	}
}

